      title VARCHAR(100) NOT NULL
    )
  )").value();

  conn->execute(R"(
    CREATE TABLE Enrollment (
      enrollment_id INTEGER PRIMARY KEY,
      course_id INTEGER,
      grade REAL,
      FOREIGN KEY (course_id) REFERENCES Course(course_id)
    )
  )").value();

  // 3. Query the database using sqlgen's fluent interface
  using namespace sqlgen::literals;

  auto query = sqlgen::select_from<Course>(
      "title"_c, 
      sqlgen::count("enrollment_id"_c).as("student_count"),
      sqlgen::avg("grade"_c).as("avg_grade")
