  sqlgen::PrimaryKey<int> order_id;
  sqlgen::ForeignKey<int, Customer, "customer_id"> customer_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
  double total_amount;
};

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  sqlgen::ForeignKey<int, Order, "order_id"> order_id;
  sqlgen::ForeignKey<int, Product, "product_id"> product_id;
  int quantity;
};

struct PurchaseHistory {
  std::string product_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
  int quantity;
};

/**
 * Function: Retrieve a customer's purchase history with product details.
 * 
 * @param customer_id ID of the customer to query
 * @return List of purchase history items
 */
std::vector<PurchaseHistory> query_customer_purchase_history(int customer_id) {
    using namespace sqlgen::literals;

    // 1. Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return {};
    }
    auto conn = *conn_result;

    // 2. Create tables if they don't exist
    (sqlgen::create_table<Customer> | sqlgen::if_not_exists)(conn);
    (sqlgen::create_table<Order> | sqlgen::if_not_exists)(conn);
    (sqlgen::create_table<OrderItem> | sqlgen::if_not_exists)(conn);
    (sqlgen::create_table<Product> | sqlgen::if_not_exists)(conn);

    // 3. Build and execute the query using sqlgen's fluent interface
    auto query = sqlgen::select_from<Customer>("name"_c.as<"product_name">(), 
                                              "order_date"_c, 
                                              "quantity"_c)
        | sqlgen::inner_join<Order>("customer_id"_c == "customer_id"_c)
        | sqlgen::inner_join<OrderItem>("order_id"_c == "order_id"_c)
        | sqlgen::inner_join<Product>("product_id"_c == "product_id"_c)
        | sqlgen::where("customer_id"_c == customer_id)
        | sqlgen::order_by("order_date"_c.desc())
        | sqlgen::to<std::vector<PurchaseHistory>>();

    // 4. Execute the query and return results
    auto result = query(conn);
    if (!result) {
        return {};
    }

    return *result;
}

}  // namespace query_customer_purchase_history
