  using namespace sqlgen::literals;

  // Cleanup and Setup
  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<User>(conn);
  create_table<User>(conn);

  // 1. Call migration_add_column
  bool success = migration_add_column();
  EXPECT_TRUE(success);

  // 2. Verify new columns exist and are usable
  // We can do this by trying to insert data using the UserAfter struct which contains the new columns
  UserAfter user_new{
      .user_id = 1,
      .username = "user_new",
      .phone_number = "1234567890",
      .is_active = true};

  // Note: sqlgen doesn't automatically map UserAfter to "User" table unless we specify it or rename struct.
  // But insert<UserAfter> will try to insert into "UserAfter" table by default.
  // So we need to use `insert` into "User" table with fields.
  // Or we can just use raw SQL to verify or use a struct with same name in a different namespace/scope if we want to map to "User".
  // Since we defined UserAfter but table name is User, sqlgen default mapping might use struct name.
  // Let's use raw SQL insert to verify the columns accept data, or `exec`.

  auto insert_res = exec(conn, "INSERT INTO User (username, phone_number, is_active) VALUES ('user_test', '555-0101', 1);");
  EXPECT_TRUE(insert_res.has_value());

  // Verify data
  struct UserVerify {
      std::string username;
      std::string phone_number;
      int is_active;
  };

  // We need to read back. sqlgen::read needs a struct that maps to the table. 
  // If we use UserAfter, it maps to "UserAfter" table.
  // We can use `select_from` with custom table name alias if supported, or just `exec` with callback/result processing?
  // sqlgen's `read` reads from table matching struct name.
  // So let's define a local struct `User` that matches the new schema for reading purposes, 
  // but since we can't redefine `User` in same namespace easily without conflict if we included header.
  // We can check with `pragma table_info` as suggested in task instructions.

  auto check_cols = exec(conn, "PRAGMA table_info('User');");
  EXPECT_TRUE(check_cols.has_value());

  // To truly verify columns exist via code, we can try to select them.
  auto select_res = exec(conn, "SELECT phone_number, is_active FROM User WHERE username = 'user_test';");
  EXPECT_TRUE(select_res.has_value());
}

